#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int x1[N], y1[N], x2[N], y2[N];
        for (int i = 0; i < N; i++) {
            scanf("%d %d %d %d", &x1[i], &y1[i], &x2[i], &y2[i]);
        }
        for (int i = 0; i < N; i++) {
            int contained = 0;
            for (int j = 0; j < N; j++) {
                if (i != j && x1[j] <= x1[i] && x2[i] <= x2[j] && y1[j] <= y1[i] && y2[i] <= y2[j]) {
                    printf("%d\n", j);
                    contained = 1;
                    break;
                }
            }
            if (!contained) {
                printf("-1\n");
            }
        }
    }
    return 0;
}

