import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[][] rooms = new int[N][4];
            for (int i = 0; i < N; i++) {
                rooms[i][0] = sc.nextInt();
                rooms[i][1] = sc.nextInt();
                rooms[i][2] = sc.nextInt();
                rooms[i][3] = sc.nextInt();
            }
            for (int i = 0; i < N; i++) {
                int contained = 0;
                for (int j = 0; j < N; j++) {
                    if (i != j && rooms[j][0] <= rooms[i][0] && rooms[i][2] <= rooms[j][2] && rooms[j][1] <= rooms[i][1] && rooms[i][3] <= rooms[j][3]) {
                        System.out.println(j);
                        contained = 1;
                        break;
                    }
                }
                if (contained == 0) {
                    System.out.println(-1);
                }
            }
        }
    }
}

